#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
CI MAXN=5e4+5;
int f[MAXN],v[MAXN],c,h;
signed main(void)
{
	c=read(),h=read();
	FOR(i,1,h)
    {
        v[i]=read();
    }
	FOR(i,1,h)
	{
		ROF(j,c,v[i])
		{
			f[j]=max(f[j],f[j-v[i]]+v[i]);
		}
		if(f[c]==c)
		{
			write(c);
			return false;
		}
	}
	write(f[c]);
	return false;
}
